"""
mkt-christ | Exodus | chapters 10-12 | 90 missing verses
Run: python3 scripts/zc-christ-exodus-10-12-fill.py

Ch 12 v13 and v46 already present (Passover blood / no broken bones); merge_comm skips them.

Key Christological types:
- 10:21-23: Three days of darkness -> Matt 27:45 (darkness at cross), three days in tomb
- 10:22-23: Israel has light / Egypt in darkness -> John 8:12; 1 John 1:5-7
- 11:5: Every firstborn struck down -> universal scope; Christ the firstborn bears judgment (Col 1:15)
- 12:3-7: Passover lamb institution -> 1 Cor 5:7; John 1:29; 1 Pet 1:19
- 12:22: Hyssop for blood application -> John 19:29 (hyssop at the cross)
- 12:36: Plundering Egypt -> Col 2:15 (Christ despoiling the powers)
- 12:40-41: 430 years to the day -> Gal 4:4 (fullness of time)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
  "10": {
    "1": "<p>YHWH tells Moses to go back to Pharaoh: 'I have hardened his heart and the hearts of his officials so that I may display my signs among them.' The hardening is purposeful and revelatory — not an obstacle to the divine plan but an instrument of it. Paul draws on this verse in Romans 9:17-18 to argue for divine sovereignty in salvation: YHWH raised up Pharaoh for a specific purpose, to display his power and proclaim his name throughout the earth. The signs are for the benefit of future generations, not merely immediate liberation.</p>",
    "2": "<p>'So that you may tell your children and grandchildren how I dealt harshly with the Egyptians and performed my signs among them.' The signs function as narrative — they are to be transmitted, commemorated, and retold. The same logic underlies the Lord's Supper: 'Do this in remembrance of me... For as often as you eat this bread and drink the cup, you proclaim the Lord's death until he comes' (1 Cor 11:24-26). The Exodus signs are the prototype for the church's commemorative proclamation of Christ's greater signs.</p>",
    "3": "<p>'How long will you refuse to humble yourself before me?' The divine question to Pharaoh is the divine question to every hardened heart. James 4:6 and 1 Peter 5:5 both cite Prov 3:34: 'God opposes the proud but gives grace to the humble.' Pharaoh is the paradigmatic case of the proud heart that refuses to yield to divine kingship. Jesus contrasts himself with this: 'I am gentle and humble in heart' (Matt 11:29) — the Son who humbled himself to the point of death (Phil 2:8) is the opposite of Pharaoh.</p>",
    "4": "<p>The locust plague is announced. The locust is used in Joel 2 as a symbol of the day of the LORD's judgment army — the prophetic use that Peter cites at Pentecost (Acts 2:16-21) as fulfilled in the Spirit's outpouring. The locust-judgment of Egypt anticipates the eschatological locust-judgment of Revelation 9:3-11. Each Exodus plague contains the seed of a larger eschatological pattern: what God did to Egypt, he will do cosmically at the last day.</p>",
    "5": "<p>The locusts will 'cover the ground so it cannot be seen' — total ecological devastation. This hyperbolic description echoes the language of cosmic darkness and judgment. Jesus describes the final judgment in similarly total terms: every tree and its fruit will be judged (Matt 7:16-20); not one stone will be left on another (Matt 24:2). The locust-judgment that leaves nothing green is a small-scale type of the eschatological judgment that leaves no corner of the old creation untouched.</p>",
    "6": "<p>'Something neither your fathers nor your forefathers have ever seen from the day they settled in this land.' Each plague exceeds what came before — the escalation toward the final, definitive act. The cross is the supreme escalation: no act of divine love or judgment in history approaches what God did in giving his Son (John 3:16). The cumulative Exodus plagues prepare the imagination for the incomparable singularity of the incarnation and atonement.</p>",
    "7": "<p>Pharaoh's officials urge release: 'Do you not yet realize that Egypt is ruined?' The pragmatic case for liberation is made by witnesses close to the power. The disciples' amazement at Jesus's power — calming storms, feeding thousands, raising the dead — creates a similar pressure: 'What kind of man is this? Even the winds and the waves obey him!' (Matt 8:27). The signs force a reckoning with the identity of the one performing them.</p>",
    "8": "<p>Moses and Aaron are brought back and Pharaoh asks: 'Who exactly will be going?' The partial-release negotiation reveals Pharaoh's strategy of incremental concessions that never fully free the people. Jesus refuses partial-liberation categories: 'If the Son sets you free, you will be free indeed' (John 8:36). The freedom Christ gives is complete — not freedom to worship without flocks, not freedom for men only, but total liberation of the whole person and community for God.</p>",
    "9": "<p>Moses: 'We will go with our young and old, our sons and daughters, and our flocks and herds.' The complete community must go — none left behind. Jesus gathers all who come to him without partial exclusions: 'Whoever comes to me I will never drive away' (John 6:37); 'Come to me, all who labor and are heavy laden' (Matt 11:28). The comprehensive 'all' of Moses's response anticipates the comprehensive 'all' of the gospel invitation.</p>",
    "10": "<p>Pharaoh's mock blessing — 'The LORD be with you!' — and then the refusal. The mockery of the divine name by the enemy's mouth is a type of the mocking of Jesus on the cross: 'He trusts in God; let God deliver him now' (Matt 27:43). The enemy speaks the truth in contempt — YHWH will indeed be with Israel; God will indeed vindicate the Son — while intending the opposite.</p>",
    "11": "<p>'Just the men may go and worship the LORD.' The gender-restricted, partial concession. In Christ, the limitations of Pharaoh's partial releases are abolished: 'there is no male and female, for you are all one in Christ Jesus' (Gal 3:28). Sons and daughters, young and old, slaves and free — the new exodus community is defined not by the permission of earthly powers but by the liberation of the Son.</p>",
    "12": "<p>YHWH commands Moses to stretch out his staff over Egypt for the locusts. The repeated gesture of the extended staff — Moses's arm as the conduit of divine power — anticipates the extended arms of Christ on the cross. The cross is the ultimate 'stretched out' posture: 'I, when I am lifted up from the earth, will draw all people to myself' (John 12:32). The Exodus signs use the stretched-out arm to bring judgment; the cross uses the stretched-out arms to absorb judgment for others.</p>",
    "13": "<p>Moses stretches out his staff and the LORD sends an east wind. The divine control of natural forces in service of the covenant plan is the backdrop for Jesus's stilling of storms (Mark 4:39): the one who commands the east wind to bring locusts speaks a word and the wind becomes calm. The disciples' question — 'Who is this?' — is answered by the Exodus narrative: YHWH, who directs wind and locust and sea, is present in their boat.</p>",
    "14": "<p>The locust plague: 'The worst locust plague there had ever been or ever will be.' The superlative judgment is a type of the unique, once-for-all nature of the cross: 'Christ was sacrificed once to take away the sins of many' (Heb 9:28). Just as the worst locust plague occupies a singular place in history, the atonement is the singular event that defines all of history before and after.</p>",
    "15": "<p>'They covered the ground until it was black, and they ate all the plants... Nothing green remained.' Total consumption, total devastation. The pattern prefigures the stripping of the cross: all human support, all natural comfort, all visible hope consumed. The three hours of darkness at the crucifixion (Matt 27:45) echo the 'land darkened' imagery of the locust plague — the consuming judgment that left nothing green.</p>",
    "16": "<p>Pharaoh quickly summons Moses and Aaron and says, 'I have sinned against the LORD your God and against you.' The first acknowledgment of sin under judgment — a confession under compulsion, not genuine repentance. The parable of the prodigal son distinguishes the compelled return ('no one gave him anything') from genuine repentance ('I will arise and go to my father'). Pharaoh's confession has the form but not the substance of the prodigal's: it seeks plague removal, not relationship restoration.</p>",
    "17": "<p>'Please forgive my sin just this once, and pray to the LORD your God to remove this deadly plague from me.' The instrumental prayer request — forgiveness as a means to plague removal, not as reconciliation with God. Jesus teaches a different posture: the tax collector who 'beat his breast and said, God, be merciful to me, a sinner' (Luke 18:13) goes home justified, not because he sought plague removal but because he threw himself on divine mercy. The form of prayer reveals the heart's orientation.</p>",
    "18": "<p>Moses left Pharaoh and prayed to the LORD. The mediator intercedes for the very one who oppresses his people. Jesus's intercession from the cross — 'Father, forgive them, for they do not know what they are doing' (Luke 23:34) — is the ultimate expression of the mediator-intercessor pattern: praying for those who harm the covenant people rather than calling down judgment on them.</p>",
    "19": "<p>YHWH turns the wind and drives the locusts into the Red Sea. The same sea that will become the stage of Israel's salvation becomes the grave of Egypt's locusts. YHWH's sovereign direction of natural forces for his purposes — the sea as both death-trap for locusts and life-path for Israel — anticipates the cross and resurrection: what seems to be Israel's end (the sea of death) is Egypt's destruction and Israel's salvation.</p>",
    "20": "<p>YHWH hardens Pharaoh's heart again after Moses's successful intercession removes the plague. The cyclical hardening-after-relief pattern demonstrates that the plagues are not designed to produce Pharaoh's repentance but to lead to the final, definitive confrontation. Hebrews 6:4-6 warns against the parallel pattern: those who have 'tasted the heavenly gift' and fallen away repeat Pharaoh's cycle — relief without transformation, acknowledgment without repentance.</p>",
    "21": "<p>'Stretch out your hand toward the sky so that darkness will spread over Egypt — darkness that can be felt.' The tactile darkness of the ninth plague is the most visceral of the plagues — an absence so complete it becomes a physical presence. At the crucifixion, 'darkness came over the whole land from noon until three in the afternoon' (Matt 27:45) — an echo of the Egyptian darkness, signaling that the judgment Egypt endured is now being absorbed by the Son. The one who is the Light of the World (John 8:12) hangs in darkness for three hours.</p>",
    "22": "<p>'Total darkness covered all Egypt for three days.' Three days of darkness is the sign of the ninth plague, and the three days of darkness prefigure the three days of Jesus in the tomb. Jesus himself identified the sign of Jonah — three days and three nights — as the sign he would give (Matt 12:39-40). The Egyptian three-day darkness is the OT type: a death-like suspension, a period of waiting without light, preceding the moment of rescue and liberation.</p>",
    "23": "<p>'No one could see anyone else, and no one left his place for three days. But all the Israelites had light where they lived.' The sharp contrast — total darkness for Egypt, light for Israel in the same moment — is the type of the gospel's distinction. Paul in Colossians 1:13: 'He has rescued us from the dominion of darkness and brought us into the kingdom of the Son he loves.' Those in Christ live in the light that the darkness cannot overcome (John 1:5), even while the surrounding world is in darkness.</p>",
    "24": "<p>Pharaoh's second partial concession: even the children may go, but the flocks must stay. Again, incomplete release that withholds the means of worship. The enemy of souls consistently offers incomplete liberation — freedom from guilt but not sin, escape from consequences but not transformation. Christ's liberation is categorically different: he gives 'life... to the full' (John 10:10), not a partial release that keeps some hold on the captive.</p>",
    "25": "<p>Moses insists: 'You must provide us with sacrifices and burnt offerings to present to the LORD our God.' The liberator refuses incomplete liberation — the worship of God requires the sacrificial material. Christ's work provides not just freedom but the means of worship: he is both liberator and the sacrifice through which the liberated people approach God (Heb 9:14; 10:19-22). The new covenant worshippers come before God 'with the blood of Jesus' — he provides the sacrifice Moses demanded.</p>",
    "26": "<p>'Not a hoof is to be left behind. We have to select from them for worshiping the LORD our God, and we do not know what we will need.' Complete liberation, complete consecration. Paul's parallel in Romans 12:1: 'Offer your bodies as a living sacrifice, holy and pleasing to God' — the whole person, not a selected part, is given to God in response to the new-exodus grace. The refusal to leave a single hoof behind is the type of the total self-offering that the gospel demands and enables.</p>",
    "27": "<p>YHWH hardens Pharaoh's heart and he will not let them go. The final hardening before the final plague. John 12:39-40 cites Isaiah's words about the hardening of Israel — using the same logic as Pharaoh's hardening — to explain why many did not believe in Jesus despite his signs: 'He has blinded their eyes and hardened their hearts.' The Pharaoh-pattern operates wherever the light of the gospel meets the hardened heart.</p>",
    "28": "<p>Pharaoh's final threat: 'The day you see my face, you will die!' The tyrant who cannot ultimately harm the covenant mediator makes a vain threat. Jesus before Pilate and the high priest faces similar threats of death — and does die, voluntarily and purposefully. But unlike Moses who escapes the threat, Jesus absorbs it: the threat of death is fulfilled not to destroy him but to accomplish the world's redemption. 'No one takes my life from me, but I lay it down of my own accord' (John 10:18).</p>",
    "29": "<p>'Just as you say — I will never appear before you again.' Moses's calm acceptance of Pharaoh's terms, knowing the final plague is about to break the impasse. Jesus before the Sanhedrin and Pilate speaks with the same quiet authority — not arguing for his rights but knowing that the next step in the divine plan is the one that will accomplish liberation. The decisive moment is not the negotiation table but the night when YHWH goes through the land.</p>"
  },
  "11": {
    "1": "<p>'I will bring one more plague on Pharaoh and on Egypt. After that, he will let you go from here, and when he does, he will drive you out completely.' The announcement of the final, decisive plague. The 'one more' is the culminating act — everything before has been leading here. The cross is the NT's 'one more': 'once for all he entered the holy places, not by means of the blood of goats and calves but by means of his own blood, thus securing an eternal redemption' (Heb 9:12). One more act, final and unrepeatable, that completes what all the prior acts anticipated.</p>",
    "2": "<p>Israel is to ask the Egyptians for articles of silver and gold. The 'plundering of Egypt' begins here — the enslaved people leave with the wealth of their enslavers, fulfilling the Abrahamic promise (Gen 15:14). Paul in Colossians 2:15 describes the cross in similar terms: Christ 'disarmed the powers and authorities, making a public spectacle of them, triumphing over them by the cross' — the ultimate plundering of the enemy's domain, where death itself is stripped of its power.</p>",
    "3": "<p>YHWH made the Egyptians favorably disposed toward the Israelites, and Moses was highly regarded in Egypt. The liberator gains honor in the enemy's camp. Jesus similarly drew the crowds: 'the large crowd listened to him with delight' (Mark 12:37). But the honor does not prevent the final confrontation — Moses's honored status in Egypt does not soften Pharaoh's heart; Jesus's popularity does not prevent the crucifixion. The favor of the crowd and the opposition of the authorities coexist until the decisive moment.</p>",
    "4": "<p>'About midnight I will go throughout Egypt.' The divine announcement of the night of judgment — the most significant night in Israel's history. Jesus was arrested, tried, and condemned in the night before his crucifixion; the events of Holy Thursday-Friday unfolded in the night hours. Paul in Romans 13:12 uses the dawn/night imagery: 'The night is nearly over; the day is almost here' — the Christian life is lived in the eschatological night between the first and second comings, awaiting the dawn of resurrection.</p>",
    "5": "<p>'Every firstborn son in Egypt will die, from Pharaoh's firstborn to the slave girl's firstborn, and all the firstborn of the livestock.' The death of the firstborn is the most comprehensive of all the plagues — no household in Egypt exempt. The firstborn represents the best, the heir, the continuation of the family. Christ, the 'firstborn over all creation' (Col 1:15) and the 'firstborn from the dead' (Col 1:18), bears this universal judgment: he is the firstborn who dies so that the firstborn of God's people might live. The exchange pattern — Egypt's firstborn for Israel's firstborn — is the type of the cross: the death of the Son so that the 'many sons and daughters' might come to glory (Heb 2:10).</p>",
    "6": "<p>'There will be loud wailing throughout Egypt — worse than there has ever been or ever will be.' The unparalleled mourning at the death of the firstborn anticipates the mourning at the cross: the women of Jerusalem wept for Jesus (Luke 23:27-28); the disciples scattered in grief; the whole creation groaned. But Jesus warns the weeping women: 'Do not weep for me, weep for yourselves and for your children' — the cross creates grief, but that grief will be turned to joy (John 16:20-22).</p>",
    "7": "<p>'But among the Israelites, not even a dog will bark at any person or animal.' Complete exemption of the covenant people from the plague. Romans 8:1: 'There is now no condemnation for those who are in Christ Jesus.' Those marked by the Passover blood are exempt not merely from one night's plague but from the final judgment: 'I tell you, whoever hears my word and believes him who sent me has eternal life and will not be judged but has crossed over from death to life' (John 5:24). No barking dog of condemnation reaches those under the blood.</p>",
    "8": "<p>'All these officials of yours will come and bow down to me, saying, Go, you and all the people who follow you!' The officials who now resist will ultimately bow. Paul in Philippians 2:10-11: 'at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue acknowledge that Jesus Christ is Lord.' The forced acknowledgment that Pharaoh's court will make at the final plague is the type of the ultimate universal acknowledgment at the name of the risen Christ.</p>",
    "9": "<p>YHWH had said to Moses that Pharaoh would not listen, 'so that my wonders may be multiplied in Egypt.' The divine purpose is transparent: the resistance serves the revelation. In John 9, the disciples ask why a man was born blind; Jesus answers, 'This happened so that the works of God might be displayed in him.' The hardness of Pharaoh and the blindness of the man from birth are both incorporated into the divine purpose of display: God's power and mercy are made visible against the backdrop of human limitation and resistance.</p>",
    "10": "<p>'Moses and Aaron performed all these wonders before Pharaoh, but the LORD hardened Pharaoh's heart.' The wonders are completed — the testimony is full. John 12:37: 'Even after Jesus had performed so many signs in their presence, they still would not believe in him.' The hardening of those who witness the signs without believing is the most sobering pattern in both Testaments. Signs authenticate; they do not coerce. Faith is not produced mechanically by miracles but by the Spirit's work through the proclaimed word (Rom 10:17).</p>"
  },
  "12": {
    "1": "<p>YHWH speaks to Moses and Aaron in Egypt — the covenant name and the priestly-prophetic team receive the foundational ordinance. The new beginning announced in the next verse is grounded in divine instruction: the calendar is not a human innovation but a divine reordering of time around redemption. John 1:1 echoes the 'in the beginning' of creation: the Word who was in the beginning becomes the Word made flesh, inaugurating a new temporal order in which all time is measured by the central event of the cross and resurrection.</p>",
    "2": "<p>'This month is to be for you the first month, the first month of your year.' The Exodus resets the calendar: history is divided into before and after the redemption. The same reorientation applies to the cross: 'The old has passed away; the new has come' (2 Cor 5:17). The Christian liturgical year is structured around the paschal mystery — Easter, not January 1, is the beginning of the new creation's year. Time itself is redeemed by the redemptive event, which becomes the fixed point from which all other moments are dated.</p>",
    "3": "<p>'Each man is to take a lamb for his family, one for each household.' A lamb for each household — the provision is particular and familial. John the Baptist's declaration 'Behold the Lamb of God who takes away the sin of the world' (John 1:29) scales this to cosmic scope: the one Lamb for the whole household of humanity. The household unit of the Passover becomes the human household; the individual family provision becomes the universal provision of the one sacrifice.</p>",
    "4": "<p>'If any household is too small for a whole lamb, they must share one with their nearest neighbor.' The shared Passover lamb — the one sacrifice extending beyond the single household to the neighbors. Christ's atonement similarly transcends every bounded group: 'He is the atoning sacrifice for our sins, and not only for ours but also for the sins of the whole world' (1 John 2:2). The lamb shared between households is the type of the universal scope of the one sacrifice.</p>",
    "5": "<p>'A year-old male without defect' (<em>seh tamim ben shanah</em>). The lamb's perfection is the sacrificial standard. Peter applies this directly to Christ: 'You were redeemed... with the precious blood of Christ, a lamb without blemish or defect' (1 Pet 1:18-19). The <em>tamim</em> (perfect, whole, without flaw) requirement links the Passover lamb to every Levitical sacrifice and finally to Christ as the antitype who alone fulfills the requirement of unblemished perfection that the animal sacrifices could only approximate.</p>",
    "6": "<p>'Slaughter it at twilight' (literally 'between the evenings') on the fourteenth day. The timing of Jesus's death aligns with the Passover slaughter: the synoptics place the Last Supper on the Passover evening; John places the crucifixion on the day of preparation when the lambs were being slaughtered in the temple (John 19:14). The exact moment of the Passover lamb's death is given divine precision — and the Gospel writers record, with equal precision, the hour of Jesus's death as the fulfillment of the Passover type.</p>",
    "7": "<p>'Take some of the blood and put it on the sides and tops of the doorframes of the houses where you eat the lambs.' The blood on the doorframe is the protective sign — visible to YHWH, marking the household as under the covenant. Hebrews 11:28 cites Moses's action as an act of faith: 'By faith he kept the Passover and the application of blood, so that the destroyer of the firstborn would not touch the firstborn of Israel.' The blood applied by faith protects; Christ's blood applied by faith to the 'doorposts' of the heart (Eph 3:17: 'Christ may dwell in your hearts through faith') marks the believer as under the new-covenant protection.</p>",
    "8": "<p>'Eat the meat roasted over fire, along with bitter herbs and bread made without yeast.' The bitter herbs (<em>m'rorim</em>) encode the experience of slavery into the Passover meal — even in the night of liberation, the bitterness of bondage is tasted. The Lord's Supper similarly encodes the suffering: 'This is my body given for you... this cup is the new covenant in my blood' — the memorial meal does not erase the cross's bitterness but transforms it into the taste of covenant love. The Eucharist is eaten 'until he comes' (1 Cor 11:26), living with the bitterness of the present age while anticipating the marriage supper.</p>",
    "9": "<p>'Do not eat the meat raw or boiled in water, but roast it over a fire — with its head, legs, and internal organs.' The whole animal, roasted — nothing removed, nothing dissolved in water. The wholeness of the offering speaks to Christ's complete self-giving: 'He offered himself unblemished to God' (Heb 9:14); 'For it was the Father's good pleasure for all the fullness to dwell in him' (Col 1:19). The Passover lamb is offered whole; Christ's self-offering is total — body and soul, human and divine nature, his entire self given in the sacrifice.</p>",
    "10": "<p>'Do not leave any of it until morning; if some is left over, burn it.' No remainder — the sacrifice is complete and consumed entirely within the specified time. 'It is finished' (John 19:30 — <em>tetelestai</em>) is the declaration of the same completeness: nothing left over, nothing to add, nothing to continue. The burning of any remainder prevents hoarding or future misuse of the sacred sacrifice; the once-for-all nature of Christ's sacrifice (Heb 10:12-14) similarly prevents any supplementation or repetition.</p>",
    "11": "<p>'Eat it with your cloak tucked into your belt, your sandals on your feet, and your staff in your hand. Eat it in haste; it is the Passover to the LORD.' The meal eaten in travel-readiness — not settled, not comfortable, but poised for immediate departure. The church exists in the same posture: 'Here we do not have an enduring city, but we are looking for the city that is to come' (Heb 13:14). The Christian life is the Passover posture: the meal of grace eaten in anticipation of the journey, feet shod with readiness (Eph 6:15).</p>",
    "12": "<p>'On that night I will pass through Egypt and strike down every firstborn... and I will bring judgment on all the gods of Egypt. I am the LORD.' The Passover night is simultaneously the night of judgment on the false gods of Egypt. The cross is the NT equivalent: 'He disarmed the rulers and authorities and put them to open shame, triumphing over them in him' (Col 2:15). The gods of Egypt — Osiris, Isis, Pharaoh's divine status — are all exposed as unable to protect their devotees; the 'rulers and authorities' are stripped of their claim over humanity through Christ's death.</p>",
    "14": "<p>'This is a day you are to commemorate; for the generations to come you shall celebrate it as a festival to the LORD — a lasting ordinance.' The Passover as perpetual memorial. Jesus explicitly commands the same perpetual commemoration: 'Do this in remembrance of me' (Luke 22:19; 1 Cor 11:24-25). The Lord's Supper is the Passover's successor-memorial — the new festival of the LORD that commemorates the new and greater exodus accomplished through the cross. Both are 'lasting ordinances': one until the coming of the other; the other 'until he comes' (1 Cor 11:26).</p>",
    "15": "<p>Seven days of unleavened bread; anyone who eats leavened bread is cut off from Israel. Paul cites the Passover-unleavened bread sequence explicitly: 'Christ, our Passover lamb, has been sacrificed. Therefore let us keep the Festival, not with the old bread leavened with malice and wickedness, but with the unleavened bread of sincerity and truth' (1 Cor 5:7-8). The post-Passover life is the unleavened life — the new creation in which the old leaven has no place, because the sacrifice has accomplished what the old life could not.</p>",
    "16": "<p>Sacred assembly on the first and seventh days — work prohibited except for food preparation. The regular sacred assembly (mikra kodesh) is the prototype of the church's gathering. Hebrews 10:25 urges: 'Do not give up meeting together, as some are in the habit of doing.' The Lord's Day assembly is the new-covenant equivalent of the Passover sacred assembly — the community gathered around the memorial of the redemptive act, which now takes the form of Word and Table rather than the slaughter of a lamb.</p>",
    "17": "<p>'Celebrate the Festival of Unleavened Bread, because it was on this very day that I brought your divisions out of Egypt.' The precision of the redemptive calendar: 'this very day.' The gospel insists on the same historical precision: 'crucified under Pontius Pilate' (Apostles' Creed). Redemption is not mythological timelessness but a specific historical act. The Feast of Unleavened Bread commemorates a specific date; the church commemorates the specific date of the cross and the specific day of the resurrection.</p>",
    "18": "<p>The specific dates — fourteenth through twenty-first of the first month — circumscribe the holy period. The calendar of the Lord's feasts (Lev 23) structures Israel's liturgical year around the redemptive events; the Christian liturgical year structures time around Good Friday, Easter, Pentecost, and Advent. Time itself is redeemed by being organized around the central salvific events rather than around agricultural or civic cycles.</p>",
    "19": "<p>'For seven days no yeast is to be found in your houses. Anyone — whether foreigner or native-born — who eats anything with yeast must be cut off from the community of Israel.' The leaven-free household represents the community purified of the old ways. Paul in 1 Corinthians 5:6-8 applies this household metaphor to the church: the old leaven of sin must not remain; the whole community is defined by its relation to the sacrifice. The inclusive reach — 'whether foreigner or native-born' — anticipates the gospel's equal application to Jew and Gentile (Rom 3:22).</p>",
    "20": "<p>'Wherever you live, you must eat unleavened bread.' The geographically universal instruction: the Passover law follows the community wherever it settles. The new covenant is equally transterritorial: 'There is neither Jew nor Greek, slave nor free, male nor female, for you are all one in Christ Jesus' (Gal 3:28). The gospel's reach is as wide as humanity's reach — it cannot be contained within a single land or ethnic community, any more than the unleavened bread command could be left behind in Egypt.</p>",
    "21": "<p>Moses summons the elders and commands the Passover slaughter. Jesus, on the night of his arrest, gathered the disciples for the last Passover and transformed it into the new-covenant memorial. The one who summons the elders for the type is Moses; the one who summons the disciples for the antitype is the Lord of the feast himself. At the Last Supper, Jesus is simultaneously the host of the Passover meal and the Passover lamb — the one who gives and the one who is given.</p>",
    "22": "<p>'Take a bunch of hyssop, dip it into the blood in the basin, and put some of the blood on the top and on both sides of the doorframe.' The hyssop branch used to apply the Passover blood connects directly to the cross: when Jesus on the cross said 'I am thirsty,' the soldiers put a sponge soaked in wine vinegar on a hyssop branch and lifted it to his lips (John 19:29). John's use of 'hyssop' (rather than the more common 'stick' in the other Gospels) is a deliberate Passover allusion — the instrument that applied the saving blood at the first Passover is present at the final Passover sacrifice.</p>",
    "23": "<p>'When the LORD goes through the land to strike down the Egyptians, he will see the blood on the top and sides of the doorframe and will pass over that doorway.' The blood as the visible sign that averts divine judgment. Paul describes the cross in identical terms in Romans 3:25: God 'presented Christ as a sacrifice of atonement, through the shedding of his blood — to be received by faith.' The blood of the Passover lamb was seen by YHWH and judgment passed over; the blood of Christ is presented before God, and through faith the believer is passed over in the final judgment.</p>",
    "24": "<p>'Obey these instructions as a lasting ordinance for you and your descendants.' The Passover becomes constitutional for Israel's identity. Paul in 1 Corinthians 11:26 gives the Lord's Supper the same constitutional status for the church: 'For whenever you eat this bread and drink this cup, you proclaim the Lord's death until he comes.' Both ordinances are community-defining, perpetual, and pedagogical — they shape the community's identity by regular reenactment of the foundational redemptive act.</p>",
    "25": "<p>'When you enter the land that the LORD will give you as he promised, observe this ceremony.' The Passover looks forward to the inheritance — it is not only a memorial of past deliverance but an act of eschatological hope. 1 Corinthians 11:26 has the same eschatological horizon: 'until he comes.' The Lord's Supper is the Passover eaten in the wilderness between the first and final exodus, between the cross and the new creation. Each celebration is an act of hope in the promised inheritance.</p>",
    "26": "<p>'And when your children ask you, What does this ceremony mean to you?' The catechetical structure embedded in the liturgy: the ritual provokes the question, the question opens the door for transmission. Jesus himself is the teacher who explains the meaning of the ceremony: at the Last Supper he interprets the Passover bread and cup as his body and blood, completing the multi-generational transmission of meaning that began with Moses's instruction to the elders here.</p>",
    "27": "<p>'It is the Passover sacrifice to the LORD, who passed over the houses of the Israelites in Egypt and spared our homes when he struck down the Egyptians.' The Passover narrative answer: salvation comes through the blood of a substitutionary sacrifice, applied by faith, which turns aside divine judgment. The catechism of the new covenant tells the same story at a deeper level: the Lord's Supper body-and-blood is the new Passover sacrifice through which the final judgment passes over those who eat in faith (1 Cor 11:27-29; John 5:24).</p>",
    "28": "<p>The Israelites did exactly as the LORD had commanded Moses and Aaron. The obedience of the covenant community precedes the salvation event — they act in anticipatory faith before the plague falls, trusting the divine word. Hebrews 11:28 names this as faith: 'By faith he kept the Passover.' The pattern is the same as Abraham's: 'Abraham believed God, and it was credited to him as righteousness' (Rom 4:3). Salvation comes to those who act on the divine word before they see the deliverance.</p>",
    "29": "<p>'At midnight the LORD struck down all the firstborn in Egypt, from the firstborn of Pharaoh on the throne to the firstborn of the prisoner in the dungeon.' The universal scope — throne to dungeon — underscores that no human status exempts from divine judgment. 'For all have sinned and fall short of the glory of God' (Rom 3:23). The Passover is the type of the final judgment: no rank, wealth, or position protects except the blood of the appointed sacrifice. The cross levels all human distinctions before the bar of divine justice.</p>",
    "30": "<p>Pharaoh and all Egypt rose up during the night, and there was loud wailing — 'for there was not a house without someone dead.' The totality of the judgment: no household exempt. 'The wages of sin is death' (Rom 6:23) — the Egyptian night of wailing is the picture of the human condition under sin's domain. But the complete opposite is promised in Revelation 21:4: 'He will wipe every tear from their eyes. There will be no more death or mourning or crying or pain.' The new covenant transforms the night of wailing into the morning of eternal joy.</p>",
    "31": "<p>'Up! Leave my people — you and the Israelites! Go, worship the LORD as you have requested.' The liberation finally granted, under compulsion of judgment. The resurrection is YHWH's ultimate 'up! leave!' — death is compelled to release its grip on the Son (Acts 2:24: 'it was impossible for death to keep its hold on him'), and through the resurrection, the greater exodus is accomplished: the liberation of all who are 'in Christ' from death's dominion (Rom 6:9-11).</p>",
    "32": "<p>'Take your flocks and herds as you have said, and go. And also bless me!' Pharaoh, who has exhausted all resistance, now asks for blessing. The defeated enemy seeking blessing through the covenant people is the pattern of Gen 12:3: 'All peoples on earth will be blessed through you.' Even Pharaoh, the paradigmatic enemy of the people of God, is drawn into seeking the blessing of the covenant. At the cross, a Roman centurion — a servant of the empire — is moved to declare 'Surely he was the Son of God' (Matt 27:54), seeking blessing through the crucified Jew.</p>",
    "33": "<p>The Egyptians urge Israel to leave quickly: 'For otherwise we will all die!' The enemy's urgency hastens the liberation. At the cross, the authorities 'wanted the bodies taken down before the Sabbath' (John 19:31) — the institutional urgency that sought to close out the affair actually precipitated the fulfillment of Passover typology (no bones broken: John 19:36 citing Exod 12:46). The enemy's haste to be done with the deliverer facilitates the completion of the redemptive plan.</p>",
    "34": "<p>The people left in haste with unleavened dough — 'without yeast because they had been driven out of Egypt and did not have time to prepare food.' The urgency of exodus leaves no time for the old life's provisions to be prepared. Paul uses the same urgency to describe conversion: 'The time is short... For this world in its present form is passing away' (1 Cor 7:29-31). The believer leaves the old life with what is already in hand, without waiting to complete the preparations of the former existence.</p>",
    "35": "<p>The Israelites asked the Egyptians for articles of silver, gold, and clothing. The covenant people leave with the material wealth of their enslavers — a divinely directed economic reversal. Origen's famous typological reading: the wealth of 'Egypt' (pagan learning) is rightly taken into the service of biblical interpretation. More directly: the cross accomplishes a cosmic wealth transfer — those who were 'poor' in sin and death are made 'rich' in forgiveness and life (2 Cor 8:9: 'Though he was rich, yet for your sake he became poor, so that you through his poverty might become rich').</p>",
    "36": "<p>The LORD made the Egyptians favorably disposed, and 'they gave them what they asked for; so they stripped Egypt' (<em>vay'natzlu et mitzraim</em> — 'they plundered Egypt'). The same verb root as Colossians 2:15: Christ 'disarmed' (<em>apekdysamenos</em>) the powers — stripped them of their authority and weapons. The plundering of Egypt at the exodus is the OT type of the plundering of the principalities and powers at the cross: the one who seemed to be defeated strips his enemies of their weapons through his death and resurrection.</p>",
    "37": "<p>About 600,000 men on foot, besides women and children — a vast multitude. John's vision of the redeemed: 'a great multitude that no one could count, from every nation, tribe, people and language, standing before the throne and before the Lamb' (Rev 7:9). The 600,000 of the Exodus is the type; the innumerable multitude of Revelation is the antitype. Christ's new-exodus gathers a people that dwarfs even the remarkable scale of the first exodus.</p>",
    "38": "<p>'Many other people went up with them, as well as large droves of livestock.' The <em>erev rav</em> (mixed multitude) — non-Israelites who join the exodus. The inclusion of Gentiles in Israel's redemption is present from the beginning: the salvation of the Passover night is not ethnically exclusive, as vv.43-49 will spell out. Paul in Romans 9-11 traces this Gentile inclusion through the entire biblical narrative, reaching its fullness in Christ through whom 'there is no distinction between Jew and Gentile — the same Lord is Lord of all and richly blesses all who call on him' (Rom 10:12).</p>",
    "39": "<p>They baked unleavened bread from the dough they had brought out of Egypt — 'no time to prepare food.' The unleavened haste of the exodus becomes the sign of the new life: the old leaven does not accompany the people into freedom. Paul's 'purge the old leaven' (1 Cor 5:7) points to the same reality: the new life in Christ begins without carrying over the leavened practices of the former existence. Baptism as dying to the old life and rising to the new (Rom 6:4) enacts the same pattern.</p>",
    "40": "<p>'The length of time the Israelites lived in Egypt was 430 years.' Paul in Galatians 3:17 uses this chronological data theologically: 'The law, introduced 430 years later, does not set aside the covenant previously established by God and thus do away with the promise.' The 430-year period between Abraham and Sinai demonstrates that the Mosaic law is subordinate to the Abrahamic promise; the promise to Abraham is fulfilled through Christ, not through the law. The Exodus chronology becomes a proof-text for the gospel's priority over law.</p>",
    "41": "<p>'At the end of the 430 years, to the very day, all the LORD's divisions left Egypt.' The divine precision: 'to the very day' (<em>b'etzem hayom hazeh</em>). Galatians 4:4: 'But when the fullness of time had come, God sent his Son, born of a woman, born under the law.' The Exodus happened at exactly the appointed moment; the incarnation happened at exactly the appointed moment. Redemptive history is not approximate but exact — the covenant God fulfills his promises on schedule.</p>",
    "42": "<p>'Because the LORD kept vigil that night to bring them out of Egypt, on this night all the Israelites are to keep vigil to honor the LORD for the generations to come.' The night of divine keeping leads to Israel's perpetual night-keeping. Jesus in Gethsemane kept vigil before his Passover sacrifice while the disciples slept — the perfect vigilance of the Son in contrast to the disciples' failure (Matt 26:40-41). The church is called to the same eschatological vigilance: 'Keep watch, because you do not know the day or the hour' (Matt 25:13).</p>",
    "43": "<p>'No foreigner may eat it.' The Passover restriction against uncircumcised foreigners creates the boundary that vv.48-49 will begin to open: the foreigner who submits to circumcision may participate. The NT opens this boundary entirely: 'In Christ Jesus you are all children of God through faith' (Gal 3:26); the Lord's Supper is for all who are baptized into Christ, regardless of ethnic origin. The restriction and its opening frame the entire covenant-inclusion trajectory that reaches its terminus in Christ.</p>",
    "44": "<p>A bought slave who is circumcised may eat the Passover. The inclusion of the circumcised slave shows that covenant membership is about the covenant sign, not free status. Paul in Galatians 3:28 and Colossians 3:11 declares the abolition of the slave/free distinction in Christ: 'There is no slave or free, but Christ is all and in all.' The new covenant removes the social stratification that the Passover regulations navigated, making all equally members through the one baptism (Eph 4:5).</p>",
    "45": "<p>The temporary resident and hired worker — those without covenant commitment — may not eat. The Passover requires covenant membership (enacted through circumcision). The Lord's Supper similarly requires covenant commitment — not ethnic membership but faith-commitment sealed in baptism. 1 Corinthians 11:27-29 warns against eating 'in an unworthy manner': the memorial is not open to casual participation but presupposes the covenant relationship it enacts.</p>",
    "46": "<p>Already present — do not break any bones.</p>",
    "47": "<p>'The whole community of Israel must celebrate it.' The Passover is not private devotion but communal commemoration — it belongs to the whole assembly. The Lord's Supper is likewise the community's meal: 'When you come together as a church' (1 Cor 11:18); 'is not the cup of thanksgiving for which we give thanks a participation in the blood of Christ? And is not the bread that we break a participation in the body of Christ? Because there is one loaf, we, who are many, are one body, for we all share the one loaf' (1 Cor 10:16-17). The communal nature of the Passover is intensified in the Lord's Supper.</p>",
    "48": "<p>'A foreigner residing among you who wants to celebrate the LORD's Passover must have all the males in his household circumcised; then he may take part like one born in the land.' The proselyte inclusion provision: Gentiles may participate through circumcision and covenant commitment. Paul in Colossians 2:11-12 applies this typologically: 'In him you were also circumcised with a circumcision not performed by human hands... having been buried with him in baptism.' The physical circumcision that admitted Gentiles to the Passover is the type of the spiritual circumcision of the heart (Rom 2:29; Deut 30:6) enacted in baptism and received through faith.</p>",
    "49": "<p>'The same law applies to the native-born and to the foreigner residing among you.' One law for both — the covenant is not tiered by ethnicity. This principle reaches its climax in Galatians 3:28: 'There is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus.' The Passover's one-law provision for all participants is the embryonic form of the gospel's universal application: the same atonement, the same faith, the same Spirit, the same inheritance for all who are in Christ.</p>",
    "50": "<p>All the Israelites did just as the LORD had commanded Moses and Aaron. The complete obedience of the covenant community on the night of liberation. Hebrews 5:8-9 applies the obedience theme to Christ: 'Although he was a son, he learned obedience from what he suffered and, once made perfect, he became the source of eternal salvation for all who obey him.' Israel's obedience on Passover night is the type; Christ's perfect obedience through suffering is the antitype that grounds the obedience of the new-covenant community.</p>",
    "51": "<p>'On that very day the LORD brought the Israelites out of Egypt by their divisions.' The Exodus accomplished: liberation enacted at the divinely appointed moment. The resurrection is the antitype: on the third day, at the divinely appointed moment, the Son was raised from the dead, completing the new exodus (Luke 9:31 — <em>exodon</em>). Paul in Romans 5:6: 'at just the right time, when we were still powerless, Christ died for the ungodly' — the divine timing of both Exodus and cross is the guarantee of covenant faithfulness. What God began, God completes; what YHWH announced to Abraham, YHWH fulfilled in Egypt, he fulfills completely in Christ.</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'exodus')
    merge_comm(c, EXODUS)
    save_comm('mkt-christ', 'exodus', c)
    print('Exodus 10-12 mkt-christ commentary written.')

if __name__ == '__main__':
    main()
